What does this program print?

```cpp
#include <iostream>

class Box {
    double m_side;
public:
    Box(double s) : m_side{ s } {}
    friend double volume(const Box& b);
};

double volume(const Box& b) {
    return b.m_side * b.m_side * b.m_side;
}

int main() {
    Box cube{ 3.0 };
    std::cout << volume(cube) << "\n";
}
```

